        public static NamespaceID? GetAttributeNamespaceID(this XmlNode node, string name, string defaultNsp)
        {
            var attr = node.Attributes[name];
            if (attr == null)
                return null;
            if (!NamespaceID.TryParse(attr.Value, defaultNsp, out var value))
                return null;
