        public static bool TryGetAttributeNullable(this XmlNode node, string name, string nullAttributeName, string type, string defaultNsp, out object? propValue)
        {
            if (node.GetAttributeBool(nullAttributeName) ?? false)
            {
                propValue = null;
                return true;
            }
            propValue = null;
            switch (type)
            {
                case "id":
                    {
                        var value = node.GetAttributeNamespaceID(name, defaultNsp);
                        bool valid = value != null;
                        if (valid)
                            propValue = value;
                        return valid;
                    }
                case "idArray":
                    {
                        var valueStr = node.GetAttribute(name);
                        if (string.IsNullOrEmpty(valueStr))
                        {
                            propValue = Array.Empty<NamespaceID>();
                        }
                        else
                        {
                            propValue = valueStr.Split(' ').Select(v => NamespaceID.TryParse(v, defaultNsp, out var parsed) ? parsed : null).Where(v => v != null).ToArray();
                        }
                        return true;
                    }
                case "sprite":
                    {
                        var value = node.GetAttributeSpriteReference(name, defaultNsp);
                        if (value != null)
                        {
                            propValue = value;
                            return true;
                        }
                    }
                    break;
                case "vector2Array":
                    {
                        var valueStr = node.GetAttribute(name);
                        if (string.IsNullOrEmpty(valueStr))
                        {
                            propValue = Array.Empty<Vector2>();
                        }
                        else
                        {
                            var vectors = new List<Vector2>();
                            var strings = valueStr.Split(' ');
                            foreach (var s in strings)
                            {
                                if (ParseHelper.TryParseVector2(s, out var parsed))
                                {
                                    vectors.Add(parsed);
                                }
                            }
                            propValue = vectors.ToArray();
                        }
                        return true;
                    }
                case "vector3Array":
                    {
                        var valueStr = node.GetAttribute(name);
                        if (string.IsNullOrEmpty(valueStr))
                        {
                            propValue = Array.Empty<Vector3>();
                        }
                        else
                        {
                            var vectors = new List<Vector3>();
                            var strings = valueStr.Split(' ');
                            foreach (var s in strings)
                            {
                                if (ParseHelper.TryParseVector3(s, out var parsed))
                                {
                                    vectors.Add(parsed);
                                }
                            }
                            propValue = vectors.ToArray();
                        }
                        return true;
                    }
                case "vector2IntArray":
                    {
                        var valueStr = node.GetAttribute(name);
                        if (string.IsNullOrEmpty(valueStr))
                        {
                            propValue = Array.Empty<Vector2Int>();
                        }
                        else
                        {
                            var vectors = new List<Vector2Int>();
                            var strings = valueStr.Split(' ');
                            foreach (var s in strings)
                            {
                                if (ParseHelper.TryParseVector2Int(s, out var parsed))
                                {
                                    vectors.Add(parsed);
                                }
                            }
                            propValue = vectors.ToArray();
                        }
                        return true;
                    }
                case "vector3IntArray":
                    {
                        var valueStr = node.GetAttribute(name);
                        if (string.IsNullOrEmpty(valueStr))
                        {
                            propValue = Array.Empty<Vector3Int>();
                        }
                        else
                        {
                            var vectors = new List<Vector3Int>();
                            var strings = valueStr.Split(' ');
                            foreach (var s in strings)
                            {
                                if (ParseHelper.TryParseVector3Int(s, out var parsed))
                                {
                                    vectors.Add(parsed);
                                }
                            }
                            propValue = vectors.ToArray();
                        }
                        return true;
                    }
            }
            return false;
        }
        public static bool TryToProperty(this XmlNode node, string defaultNsp, out object? propValue)
        {
            var type = node.Name;
            if (node.TryGetAttributeStruct("value", type, out propValue))
            {
                return true;
            }
            if (node.TryGetAttributeVector(type, out propValue))
            {
                return true;
            }
            if (node.TryGetAttributeNullable("value", "null", type, defaultNsp, out propValue))
            {
                return true;
            }
            propValue = null;
            return false;
        }


        public static string ConcatNodeParagraphs(this XmlNode node)
        {
            var lineNodes = node.ChildNodes;
            var sb = new StringBuilder();
            bool first = true;
            for (int i = 0; i < lineNodes.Count; i++)
            {
                var lineNode = lineNodes[i];
                if (lineNode.Name == "p")
                {
                    if (!first)
                    {
                        sb.Append("\n");
                    }
                    first = false;
                    sb.Append(lineNodes[i].InnerText);
                }
            }
            return sb.ToString();
        }
